    /**
     * Convierte una cadena de texto de datos de ruta SVG en un objeto [Path] de Compose.
     * * Implementa un mecanismo de defensa mediante 'try-catch' para evitar fallos críticos
     * en tiempo de ejecución si el string del SVG contiene errores sintácticos.
     * * @param pathData Cadena que sigue el estándar de rutas SVG (SVG Path Data).
     * @return Objeto [Path] renderizable por el motor gráfico de Android.
     */
    private fun createPath(pathData: String): Path {
        return try {
            PathParser.createPathFromPathData(pathData).asComposePath()
        } catch (e: Exception) {
            // Loguear el error sería ideal aquí en un entorno de producción real.
            Path()
        }
    }

    /**
     * Genera un trazado circular cerrado.
     * Utilizado para representar geolocalizaciones de puntos de interés o microestados
     * donde el detalle de la frontera no es relevante a la escala actual.
     * * @param x Coordenada X del centro del círculo.
     * @param y Coordenada Y del centro del círculo.
     * @param radius Radio en unidades de dibujo.
     * @return [Path] circular.
     */
    private fun createCirclePath(x: Float, y: Float, radius: Float): Path {
        return Path().apply {
            addOval(Rect(x - radius, y - radius, x + radius, y + radius))
        }
    }
